5854   if (FMF.noNaNs()) {
5855     // X / X -> 1.0 is legal when NaNs are ignored.
5856     // We can ignore infinities because INF/INF is NaN.
5857     if (Op0 == Op1)
5858       return ConstantFP::get(Op0->getType(), 1.0);
