5864 
5865     // -X /  X -> -1.0 and
5866     //  X / -X -> -1.0 are legal when NaNs are ignored.
5867     // We can ignore signed zeros because +-0.0/+-0.0 is NaN and ignored.
5868     if (match(Op0, m_FNegNSZ(m_Specific(Op1))) ||
5869         match(Op1, m_FNegNSZ(m_Specific(Op0))))
